mapper.sql:
WHERE t.user_id = #{userId}
  AND t.deleted = 0

    AND t.type = #{type}


    AND t.occurred_at >= #{startAt}


    AND t.occurred_at < #{endAt}


    AND t.channel = #{channel}


    AND t.category_id = #{categoryId}


    AND t.payment_method_id = #{paymentMethodId}


    AND (
        t.item_name LIKE CONCAT('%', #{keyword}, '%')
        OR t.note LIKE CONCAT('%', #{keyword}, '%')
        OR t.online_app LIKE CONCAT('%', #{keyword}, '%')
        OR t.offline_place LIKE CONCAT('%', #{keyword}, '%')
        OR t.payment_method_name LIKE CONCAT('%', #{keyword}, '%')
        OR pm.name LIKE CONCAT('%', #{keyword}, '%')
        OR c.name LIKE CONCAT('%', #{keyword}, '%')
    )

mapper.select:
SELECT



ORDER BY t.occurred_at DESC, t.id DESC

    LIMIT #{limit} OFFSET #{offset}

SELECT


WHERE t.user_id = #{userId}
  AND t.id = #{id}
  AND t.deleted = 0
ORDER BY t.occurred_at DESC, t.id DESC
